{
  "name": "ScribbleToDoc",
  "description": "Transform your handwritten notes into professional Word documents using advanced OCR and batch processing.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface BatchImage {
  id: string;
  file: File | Blob;
  previewUrl: string;
  processedText?: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  progress: number;
}

export interface OCRConfig {
  language: string;
  grayscale: boolean;
  contrast: number;
  threshold: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Camera, 
  Upload, 
  FileText, 
  Download, 
  Share2, 
  Moon, 
  Sun, 
  Trash2, 
  Play, 
  Settings,
  ChevronRight,
  ChevronLeft,
  Loader2,
  CheckCircle2,
  Copy,
  Plus
} from 'lucide-react';
import { BatchImage, OCRConfig } from './types';
import CameraCapture from './components/CameraCapture';
import ImageProcessor from './components/ImageProcessor';
import Editor from './components/Editor';
import BatchList from './components/BatchList';
import { processImageOCR } from './services/ocrService';
import { generateDocx } from './services/docxService';

const App: React.FC = () => {
  const [images, setImages] = useState<BatchImage[]>([]);
  const [currentIndex, setCurrentIndex] = useState<number>(-1);
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });
  const [config, setConfig] = useState<OCRConfig>({
    language: 'eng',
    grayscale: true,
    contrast: 1.2,
    threshold: 128
  });
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [finalText, setFinalText] = useState('');

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newImages: BatchImage[] = Array.from(files).map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending',
      progress: 0
    }));

    setImages(prev => [...prev, ...newImages]);
    if (currentIndex === -1) setCurrentIndex(0);
  };

  const handleCapture = (blob: Blob) => {
    const newImage: BatchImage = {
      id: Math.random().toString(36).substr(2, 9),
      file: blob,
      previewUrl: URL.createObjectURL(blob),
      status: 'pending',
      progress: 0
    };
    setImages(prev => [...prev, newImage]);
    setIsCameraOpen(false);
    if (currentIndex === -1) setCurrentIndex(images.length);
  };

  const startBatchProcess = async () => {
    setIsProcessing(true);
    const updatedImages = [...images];
    let combinedText = '';

    for (let i = 0; i < updatedImages.length; i++) {
      if (updatedImages[i].status === 'completed') {
        combinedText += (updatedImages[i].processedText || '') + '\n\n';
        continue;
      }

      updatedImages[i].status = 'processing';
      setImages([...updatedImages]);

      try {
        const text = await processImageOCR(
          updatedImages[i].previewUrl, 
          config, 
          (progress) => {
            updatedImages[i].progress = progress;
            setImages([...updatedImages]);
          }
        );
        updatedImages[i].processedText = text;
        updatedImages[i].status = 'completed';
        combinedText += text + '\n\n';
      } catch (err) {
        updatedImages[i].status = 'error';
      }
      setImages([...updatedImages]);
    }
    setFinalText(combinedText.trim());
    setIsProcessing(false);
  };

  const handleExport = async () => {
    if (!finalText) return;
    try {
      await generateDocx(finalText, "ScribbleToDoc_Export");
    } catch (err) {
      console.error("Export failed", err);
      alert("Failed to export document. Check console for details.");
    }
  };

  const handleShare = async () => {
    if (!finalText) return;
    const shareData = {
      title: 'Handwritten Notes Export',
      text: finalText,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Share failed', err);
      }
    } else {
      navigator.clipboard.writeText(finalText);
      alert('Text copied to clipboard!');
    }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Header */}
      <header className="flex justify-between items-center mb-10">
        <div className="flex items-center gap-3">
          <div className="p-3 bg-primary-600 rounded-2xl shadow-lg shadow-primary-200 dark:shadow-none">
            <FileText className="text-white w-8 h-8" />
          </div>
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight">ScribbleToDoc</h1>
            <p className="text-slate-500 text-sm font-medium">Capture. OCR. Document.</p>
          </div>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={() => setDarkMode(!darkMode)}
            className="p-3 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
            title="Toggle Theme"
          >
            {darkMode ? <Sun className="w-6 h-6" /> : <Moon className="w-6 h-6" />}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Capture & Batch */}
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <Camera className="w-5 h-5 text-primary-500" />
                Input Source
              </h2>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => setIsCameraOpen(true)}
                className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl hover:border-primary-400 hover:bg-primary-50 dark:hover:bg-primary-900/10 transition-all group"
              >
                <Camera className="w-8 h-8 mb-2 text-slate-400 group-hover:text-primary-500" />
                <span className="text-sm font-semibold">Scan Camera</span>
              </button>

              <label className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl hover:border-primary-400 hover:bg-primary-50 dark:hover:bg-primary-900/10 transition-all group cursor-pointer">
                <Upload className="w-8 h-8 mb-2 text-slate-400 group-hover:text-primary-500" />
                <span className="text-sm font-semibold text-center">Upload Files</span>
                <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileUpload} />
              </label>
            </div>
          </section>

          <section className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
             <div className="flex items-center justify-between mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <Settings className="w-5 h-5 text-primary-500" />
                OCR Settings
              </h2>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">Language</label>
                <select 
                  className="w-full p-2 bg-slate-50 dark:bg-slate-800 rounded-lg outline-none focus:ring-2 focus:ring-primary-500"
                  value={config.language}
                  onChange={(e) => setConfig({...config, language: e.target.value})}
                >
                  <option value="eng">English</option>
                  <option value="spa">Spanish</option>
                  <option value="fra">French</option>
                  <option value="deu">German</option>
                </select>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium">Grayscale Pre-processing</span>
                <input 
                  type="checkbox" 
                  checked={config.grayscale}
                  onChange={(e) => setConfig({...config, grayscale: e.target.checked})}
                  className="w-4 h-4 rounded text-primary-600 focus:ring-primary-500"
                />
              </div>
            </div>
          </section>

          <section className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-bold">Batch Queue ({images.length})</h2>
              {images.length > 0 && (
                <button 
                  onClick={() => {setImages([]); setFinalText('');}} 
                  className="text-red-500 text-xs font-bold hover:underline"
                >
                  Clear All
                </button>
              )}
            </div>
            <BatchList 
              items={images} 
              onRemove={(id) => setImages(images.filter(img => img.id !== id))} 
              onSelect={(index) => setCurrentIndex(index)}
              activeIndex={currentIndex}
            />
            {images.length > 0 && !isProcessing && (
              <button 
                onClick={startBatchProcess}
                className="w-full mt-6 py-4 bg-primary-600 hover:bg-primary-700 text-white rounded-2xl font-bold flex items-center justify-center gap-2 transition-transform active:scale-95 shadow-lg shadow-primary-200 dark:shadow-none"
              >
                <Play className="w-5 h-5" />
                Start Conversion
              </button>
            )}
            {isProcessing && (
              <div className="mt-6 flex flex-col items-center gap-3">
                <Loader2 className="w-8 h-8 text-primary-500 animate-spin" />
                <p className="text-sm text-slate-500">Extracting handwriting...</p>
              </div>
            )}
          </section>
        </div>

        {/* Right Column: Editor & Result */}
        <div className="lg:col-span-7 space-y-6">
          <section className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 min-h-[500px] flex flex-col overflow-hidden">
            <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/50 dark:bg-slate-800/30">
              <div className="flex items-center gap-4">
                <h2 className="text-lg font-bold">Document Editor</h2>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={handleShare}
                  disabled={!finalText}
                  className="p-2.5 rounded-xl border border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 transition-colors disabled:opacity-30"
                  title="Share"
                >
                  <Share2 className="w-5 h-5" />
                </button>
                <button 
                  onClick={handleExport}
                  disabled={!finalText}
                  className="px-5 py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-xl font-bold text-sm flex items-center gap-2 hover:opacity-90 transition-opacity disabled:opacity-30"
                >
                  <Download className="w-4 h-4" />
                  DOCX
                </button>
              </div>
            </div>

            <div className="flex-1 p-6">
               <Editor 
                content={finalText} 
                onChange={(val) => setFinalText(val)} 
                placeholder="Transcribed text will appear here. You can manually edit or paste more notes..."
               />
            </div>
          </section>
        </div>
      </main>

      {/* Overlays */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-3xl w-full max-w-2xl overflow-hidden relative">
            <button 
              onClick={() => setIsCameraOpen(false)}
              className="absolute top-4 right-4 z-10 p-2 bg-black/20 rounded-full text-white hover:bg-black/40"
            >
              <Trash2 className="w-6 h-6" />
            </button>
            <CameraCapture onCapture={handleCapture} />
          </div>
        </div>
      )}

      {/* Instructions if empty */}
      {images.length === 0 && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 max-w-md w-full px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur border border-slate-200 dark:border-slate-800 rounded-2xl shadow-xl flex items-center gap-4 animate-bounce">
          <div className="p-2 bg-primary-100 rounded-lg">
            <Plus className="w-5 h-5 text-primary-600" />
          </div>
          <p className="text-sm font-medium text-slate-600 dark:text-slate-400">
            Start by uploading or scanning a handwritten note!
          </p>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { Camera, RefreshCw } from 'lucide-react';

interface Props {
  onCapture: (blob: Blob) => void;
}

const CameraCapture: React.FC<Props> = ({ onCapture }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment' },
          audio: false 
        });
        setStream(s);
        if (videoRef.current) {
          videoRef.current.srcObject = s;
        }
      } catch (err) {
        setError('Camera access denied or not available.');
      }
    };

    startCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const captureFrame = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        canvas.toBlob((blob) => {
          if (blob) onCapture(blob);
        }, 'image/jpeg', 0.95);
      }
    }
  };

  return (
    <div className="flex flex-col items-center bg-black">
      <div className="relative w-full aspect-[4/3] bg-black">
        {error ? (
          <div className="absolute inset-0 flex items-center justify-center text-white p-6 text-center">
            {error}
          </div>
        ) : (
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            className="w-full h-full object-contain"
          />
        )}
      </div>
      <div className="w-full p-8 bg-white dark:bg-slate-900 flex justify-center gap-6">
        <button 
          onClick={captureFrame}
          disabled={!!error}
          className="w-16 h-16 rounded-full bg-primary-600 flex items-center justify-center shadow-lg active:scale-90 transition-transform disabled:opacity-50"
        >
          <div className="w-12 h-12 rounded-full border-4 border-white" />
        </button>
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default CameraCapture;

import React from 'react';
import { X, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';
import { BatchImage } from '../types';

interface Props {
  items: BatchImage[];
  onRemove: (id: string) => void;
  onSelect: (index: number) => void;
  activeIndex: number;
}

const BatchList: React.FC<Props> = ({ items, onRemove, onSelect, activeIndex }) => {
  if (items.length === 0) {
    return (
      <div className="py-12 border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-2xl flex flex-col items-center justify-center text-slate-400">
        <p className="text-sm">No images in queue</p>
      </div>
    );
  }

  return (
    <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
      {items.map((item, index) => (
        <div 
          key={item.id}
          className={`group flex items-center gap-3 p-3 rounded-2xl transition-all cursor-pointer border ${
            activeIndex === index 
              ? 'bg-primary-50 dark:bg-primary-900/20 border-primary-200 dark:border-primary-800' 
              : 'bg-slate-50 dark:bg-slate-800/50 border-transparent hover:border-slate-200 dark:hover:border-slate-700'
          }`}
          onClick={() => onSelect(index)}
        >
          <div className="relative w-14 h-14 flex-shrink-0">
            <img 
              src={item.previewUrl} 
              alt="Scan" 
              className="w-full h-full object-cover rounded-xl shadow-sm"
            />
            {item.status === 'processing' && (
              <div className="absolute inset-0 bg-black/40 rounded-xl flex items-center justify-center">
                <Loader2 className="w-6 h-6 text-white animate-spin" />
              </div>
            )}
          </div>

          <div className="flex-1 min-w-0">
            <p className="text-sm font-bold truncate">Note Page #{index + 1}</p>
            <div className="flex items-center gap-2 mt-1">
              {item.status === 'completed' ? (
                <span className="flex items-center gap-1 text-[10px] font-bold text-green-500 uppercase">
                  <CheckCircle className="w-3 h-3" /> Ready
                </span>
              ) : item.status === 'error' ? (
                <span className="flex items-center gap-1 text-[10px] font-bold text-red-500 uppercase">
                  <AlertCircle className="w-3 h-3" /> Error
                </span>
              ) : item.status === 'processing' ? (
                <div className="w-full bg-slate-200 dark:bg-slate-700 h-1.5 rounded-full mt-1 overflow-hidden">
                  <div 
                    className="bg-primary-500 h-full transition-all duration-300" 
                    style={{ width: `${item.progress * 100}%` }}
                  />
                </div>
              ) : (
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Pending</span>
              )}
            </div>
          </div>

          <button 
            onClick={(e) => { e.stopPropagation(); onRemove(item.id); }}
            className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      ))}
    </div>
  );
};

export default BatchList;

import React from 'react';
import { Bold, Italic, List, Heading1, Heading2 } from 'lucide-react';

interface Props {
  content: string;
  onChange: (val: string) => void;
  placeholder?: string;
}

const Editor: React.FC<Props> = ({ content, onChange, placeholder }) => {
  const insertText = (before: string, after: string = '') => {
    const textarea = document.getElementById('main-editor') as HTMLTextAreaElement;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selectedText = text.substring(start, end);
    const newText = text.substring(0, start) + before + selectedText + after + text.substring(end);

    onChange(newText);

    // Reset focus and selection
    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + before.length, end + before.length);
    }, 0);
  };

  return (
    <div className="flex flex-col h-full border border-slate-200 dark:border-slate-800 rounded-2xl overflow-hidden focus-within:ring-2 focus-within:ring-primary-500 transition-all">
      <div className="flex items-center gap-1 p-2 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
        <button onClick={() => insertText('**', '**')} className="p-2 rounded-lg hover:bg-white dark:hover:bg-slate-700 transition-colors" title="Bold">
          <Bold className="w-4 h-4" />
        </button>
        <button onClick={() => insertText('_', '_')} className="p-2 rounded-lg hover:bg-white dark:hover:bg-slate-700 transition-colors" title="Italic">
          <Italic className="w-4 h-4" />
        </button>
        <div className="w-[1px] h-4 bg-slate-300 dark:bg-slate-600 mx-1" />
        <button onClick={() => insertText('# ')} className="p-2 rounded-lg hover:bg-white dark:hover:bg-slate-700 transition-colors" title="Heading 1">
          <Heading1 className="w-4 h-4" />
        </button>
        <button onClick={() => insertText('## ')} className="p-2 rounded-lg hover:bg-white dark:hover:bg-slate-700 transition-colors" title="Heading 2">
          <Heading2 className="w-4 h-4" />
        </button>
        <button onClick={() => insertText('- ')} className="p-2 rounded-lg hover:bg-white dark:hover:bg-slate-700 transition-colors" title="List Item">
          <List className="w-4 h-4" />
        </button>
      </div>
      <textarea
        id="main-editor"
        className="flex-1 p-6 bg-transparent outline-none resize-none text-lg font-medium leading-relaxed custom-scrollbar min-h-[400px]"
        value={content}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
      />
    </div>
  );
};

export default Editor;

import { OCRConfig } from '../types';

declare const Tesseract: any;

export const processImageOCR = async (
  imageUrl: string, 
  config: OCRConfig, 
  onProgress: (progress: number) => void
): Promise<string> => {
  // Pre-processing using canvas
  const canvas = document.createElement('canvas');
  const img = new Image();
  img.src = imageUrl;

  await new Promise((resolve) => {
    img.onload = resolve;
  });

  canvas.width = img.width;
  canvas.height = img.height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Could not get canvas context");

  ctx.drawImage(img, 0, 0);

  if (config.grayscale) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
      const avg = (data[i] + data[i + 1] + data[i + 2]) / 3;
      // Adjust contrast
      const contrastFactor = config.contrast;
      const newValue = (avg - 128) * contrastFactor + 128;

      data[i] = data[i+1] = data[i+2] = newValue;
    }
    ctx.putImageData(imageData, 0, 0);
  }

  const processedDataUrl = canvas.toDataURL('image/png');

  // Perform OCR
  const worker = await Tesseract.createWorker(config.language, 1, {
    logger: (m: any) => {
      if (m.status === 'recognizing text') {
        onProgress(m.progress);
      }
    }
  });

  const { data: { text } } = await worker.recognize(processedDataUrl);
  await worker.terminate();

  return text;
};

declare const docx: any;
declare const saveAs: any;

export const generateDocx = async (content: string, filename: string) => {
  const { Document, Packer, Paragraph, TextRun, HeadingLevel } = docx;

  // Simple Markdown-ish parser for paragraphs
  const lines = content.split('\n');
  const sections: any[] = [];

  lines.forEach((line) => {
    let text = line.trim();
    if (!text) return;

    if (text.startsWith('# ')) {
      sections.push(new Paragraph({
        text: text.substring(2),
        heading: HeadingLevel.HEADING_1,
        spacing: { before: 240, after: 120 }
      }));
    } else if (text.startsWith('## ')) {
      sections.push(new Paragraph({
        text: text.substring(3),
        heading: HeadingLevel.HEADING_2,
        spacing: { before: 200, after: 100 }
      }));
    } else if (text.startsWith('- ')) {
      sections.push(new Paragraph({
        text: text.substring(2),
        bullet: { level: 0 },
        spacing: { after: 120 }
      }));
    } else {
      // Basic support for bold/italic if needed, but keeping it simple
      sections.push(new Paragraph({
        children: [
          new TextRun({
            text: text,
            size: 24, // 12pt
          })
        ],
        spacing: { after: 120 }
      }));
    }
  });

  const doc = new Document({
    sections: [{
      properties: {},
      children: [
        new Paragraph({
          text: "Transcribed Handwritten Notes",
          heading: HeadingLevel.TITLE,
          spacing: { after: 400 }
        }),
        new Paragraph({
          children: [
            new TextRun({
              text: `Generated on: ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}`,
              italics: true,
              color: "666666"
            })
          ],
          spacing: { after: 400 }
        }),
        ...sections
      ],
    }],
  });

  const blob = await Packer.toBlob(doc);
  saveAs(blob, `${filename}.docx`);
};

