 * Accesses global 'docx' object from the loaded CDN script.
 */
export const generateDocxBlob = async (content: string, title: string = "Transcribed Notes") => {
  const globalDocx = (window as any).docx;

  if (!globalDocx) {
    console.error("Docx library not found on window object.");
    throw new Error("Docx library not loaded. Please ensure you have an active internet connection.");
  }

  const { Document, Packer, Paragraph, TextRun, HeadingLevel } = globalDocx;

  if (!Document || !Packer) {
    console.error("Docx library loaded but required properties are missing.", globalDocx);
    throw new Error("Docx library structure is unexpected. Please check CDN version.");
  }

  const lines = content.split('\n');
  const sections: any[] = [];

  lines.forEach((line) => {
    const text = line.trim();
    if (!text) return;

    if (text.startsWith('# ')) {
      sections.push(new Paragraph({
        text: text.substring(2),
        heading: HeadingLevel.HEADING_1,
        spacing: { before: 240, after: 120 }
      }));
    } else if (text.startsWith('## ')) {
      sections.push(new Paragraph({
        text: text.substring(3),
        heading: HeadingLevel.HEADING_2,
        spacing: { before: 200, after: 100 }
      }));
    } else if (text.startsWith('- ')) {
      sections.push(new Paragraph({
        text: text.substring(2),
        bullet: { level: 0 },
        spacing: { after: 120 }
      }));
    } else {
      sections.push(new Paragraph({
        children: [
          new TextRun({
            text: text,
            size: 24, // 12pt
          })
        ],
        spacing: { after: 120 }
      }));
    }
  });

  try {
    const doc = new Document({
      sections: [{
        properties: {},
        children: [
          new Paragraph({
            text: title,
            heading: HeadingLevel.TITLE,
            spacing: { after: 400 }
          }),
          new Paragraph({
            children: [
              new TextRun({
                text: `Generated on: ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}`,
                italics: true,
                color: "666666"
              })
            ],
            spacing: { after: 400 }
          }),
          ...sections
        ],
      }],
    });

    return await Packer.toBlob(doc);
  } catch (err) {
    console.error("Error during docx construction or packaging:", err);
    throw err;
  }
};

/**
 * Generates and triggers a download for a DOCX file.
 */
export const generateDocx = async (content: string, filename: string) => {
  try {
    const blob = await generateDocxBlob(content);
    const saveAs = (window as any).saveAs;

    if (saveAs) {
      saveAs(blob, `${filename}.docx`);
    } else {
      console.warn("saveAs not found, falling back to anchor-based download.");
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${filename}.docx`;
      document.body.appendChild(a);
      a.click();
      setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }, 100);
    }
  } catch (error) {
    console.error("Critical error generating DOCX download:", error);
    alert("Could not generate Word document. See console for technical details.");
    throw error;
  }
};

