import { GoogleGenAI } from "@google/genai";
import { OCRConfig } from '../types';

export const processImageOCR = async (
  imageUrl: string, 
  config: OCRConfig, 
  onProgress: (progress: number) => void,
  apiKey: string
): Promise<string> => {
  // We utilize a canvas to prepare the image and still support pre-processing options
  const img = new Image();
  img.src = imageUrl;

  await new Promise((resolve, reject) => {
    img.onload = resolve;
    img.onerror = reject;
  });

  const canvas = document.createElement('canvas');
  canvas.width = img.width;
  canvas.height = img.height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Could not get canvas context");

  ctx.drawImage(img, 0, 0);

  // Apply grayscale and contrast enhancements which often help vision models with handwritten notes
  if (config.grayscale) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
      const avg = (data[i] + data[i + 1] + data[i + 2]) / 3;
      const contrastFactor = config.contrast;
      const newValue = (avg - 128) * contrastFactor + 128;
      data[i] = data[i+1] = data[i+2] = newValue;
    }
    ctx.putImageData(imageData, 0, 0);
  }

  // Convert to high-quality JPEG for transmission to the Gemini API
  const processedDataUrl = canvas.toDataURL('image/jpeg', 0.9);
  const base64Data = processedDataUrl.split(',')[1];

  // Report initial progress
  onProgress(0.2);

  if (!apiKey) {
    throw new Error("API Key is missing. Please enter your Google Gemini API Key.");
  }

  // Initialize the Gemini API client with the user-provided key
  const ai = new GoogleGenAI({ apiKey });

  try {
    // We use gemini-3-flash-preview for high speed and excellent vision-to-text capabilities
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Data,
            },
          },
          {
            text: `Transcribe the handwritten text in this image accurately. 
            Maintain original paragraphs and structure. 
            Language: ${config.language}. 
            Output ONLY the transcribed text without any greetings or explanations.`
          },
        ],
      },
    });

    onProgress(1.0);
    return response.text || "No text detected in the image.";
  } catch (error) {
    console.error("OCR process failed with Gemini API:", error);
    throw new Error("Failed to extract text. Please check your API Key and internet connection.");
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Camera, 
  Upload, 
  FileText, 
  Download, 
  Share2, 
  Moon, 
  Sun, 
  Trash2, 
  Play, 
  Settings,
  ChevronRight,
  ChevronLeft,
  Loader2,
  CheckCircle2,
  Copy,
  Plus,
  Archive,
  AlertTriangle,
  RefreshCw,
  Key,
  X
} from 'lucide-react';
import { BatchImage, OCRConfig } from './types';
import CameraCapture from './components/CameraCapture';
import Editor from './components/Editor';
import BatchList from './components/BatchList';
import { processImageOCR } from './services/ocrService';
import { generateDocx, generateDocxBlob } from './services/docxService';

const App: React.FC = () => {
  const [images, setImages] = useState<BatchImage[]>([]);
  const [currentIndex, setCurrentIndex] = useState<number>(-1);
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });
  const [config, setConfig] = useState<OCRConfig>({
    language: 'eng',
    grayscale: true,
    contrast: 1.2,
    threshold: 128
  });
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [finalText, setFinalText] = useState('');

  // API Key State
  const [apiKey, setApiKey] = useState('');
  const [showKeyModal, setShowKeyModal] = useState(false);

  // Library loading state
  const [libsLoaded, setLibsLoaded] = useState(false);
  const [libsError, setLibsError] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Load API Key from local storage on mount
  useEffect(() => {
    const storedKey = localStorage.getItem('gemini_api_key');
    if (storedKey) {
      setApiKey(storedKey);
    } else {
      setShowKeyModal(true);
    }
  }, []);

  const handleSaveKey = (key: string) => {
    setApiKey(key);
    localStorage.setItem('gemini_api_key', key);
    setShowKeyModal(false);
  };

  const handleRemoveKey = () => {
    setApiKey('');
    localStorage.removeItem('gemini_api_key');
    setShowKeyModal(true);
  };

  const checkLibs = useCallback(() => {
    setLibsError(false);
    let attempts = 0;
    const maxAttempts = 60; // 30 seconds total (500ms * 60)

    const check = () => {
      const docxReady = (window as any).docx || (window as any).DOCX;
      const jszipReady = (window as any).JSZip;
      const saveAsReady = (window as any).saveAs;

      if (docxReady && jszipReady && saveAsReady) {
        setLibsLoaded(true);
        setLibsError(false);
      } else {
        attempts++;
        if (attempts >= maxAttempts) {
          setLibsError(true);
        } else {
          setTimeout(check, 500);
        }
      }
    };
    check();
  }, []);

  // Initial check
  useEffect(() => {
    checkLibs();
  }, [checkLibs]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newImages: BatchImage[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending',
      progress: 0
    }));

    setImages(prev => [...prev, ...newImages]);
    if (currentIndex === -1) setCurrentIndex(images.length);
  };

  const handleCapture = (blob: Blob) => {
    const newImage: BatchImage = {
      id: Math.random().toString(36).substr(2, 9),
      file: blob,
      previewUrl: URL.createObjectURL(blob),
      status: 'pending',
      progress: 0
    };
    setImages(prev => [...prev, newImage]);
    setIsCameraOpen(false);
    if (currentIndex === -1) setCurrentIndex(images.length);
  };

  const startBatchProcess = async () => {
    if (isProcessing) return;

    if (!apiKey) {
      setShowKeyModal(true);
      return;
    }

    setIsProcessing(true);
    const updatedImages = [...images];
    let accumulatedText = finalText;

    for (let i = 0; i < updatedImages.length; i++) {
      if (updatedImages[i].status === 'completed') continue;

      updatedImages[i].status = 'processing';
      setImages([...updatedImages]);

      try {
        const text = await processImageOCR(
          updatedImages[i].previewUrl, 
          config, 
          (progress) => {
            setImages(prev => prev.map((img, idx) => idx === i ? { ...img, progress } : img));
          },
          apiKey
        );
        updatedImages[i].processedText = text;
        updatedImages[i].status = 'completed';

        // Update both the queue and the editor text in real-time
        accumulatedText = accumulatedText ? accumulatedText + '\n\n' + text : text;
        setFinalText(accumulatedText);

      } catch (err) {
        console.error("OCR Error for image " + i, err);
        updatedImages[i].status = 'error';
      }
      setImages([...updatedImages]);
    }
    setIsProcessing(false);
  };

  const handleExport = async () => {
    if (!finalText) return;
    try {
      await generateDocx(finalText, "ScribbleToDoc_Notes");
    } catch (err) {
      console.error("Export failed:", err);
    }
  };

  const handleDownloadZip = async () => {
    if (!libsLoaded) {
      alert("Export libraries failed to load. Please refresh the page or check your connection.");
      return;
    }

    const JSZip = (window as any).JSZip;
    const saveAs = (window as any).saveAs;

    const completedImages = images.filter(img => img.status === 'completed');
    if (completedImages.length === 0) {
      alert("No processed notes to export. Please start conversion first.");
      return;
    }

    setIsZipping(true);
    try {
      const zip = new JSZip();

      for (let i = 0; i < completedImages.length; i++) {
        const img = completedImages[i];
        const text = img.processedText || "";
        const filename = `Note_Page_${i + 1}`;

        zip.file(`${filename}.txt`, text);

        const docBlob = await generateDocxBlob(text, `Note Page ${i + 1}`);
        zip.file(`${filename}.docx`, docBlob);
      }

      const zipBlob = await zip.generateAsync({ type: "blob" });
      saveAs(zipBlob, "ScribbleToDoc_Batch_Export.zip");
    } catch (err) {
      console.error("ZIP Generation failed:", err);
      alert(err instanceof Error ? err.message : "Failed to generate ZIP archive.");
    } finally {
      setIsZipping(false);
    }
  };

  const handleShare = async () => {
    if (!finalText) return;
    const shareData = {
      title: 'Handwritten Notes Export',
      text: finalText,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Share failed', err);
      }
    } else {
      navigator.clipboard.writeText(finalText);
      alert('Text copied to clipboard!');
    }
  };

  const processedCount = images.filter(img => img.status === 'completed').length;
  const isAllDone = images.length > 0 && processedCount === images.length;

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <header className="flex justify-between items-center mb-10">
        <div className="flex items-center gap-3">
